// Portable request-time SSR handler used by emitted Vercel functions
// (edge / node / bun). No Bun-only APIs — renders with react-dom/server.
// The per-route entry (generated by the build) supplies the modules + assets
// and exports `{ fetch }` built from makeRouteHandler().
import { createElement } from "react";

async function renderTree(tree) {
  // server.edge works across edge, node 18+, and bun.
  try {
    const { renderToReadableStream } = await import("react-dom/server.edge");
    const stream = await renderToReadableStream(tree);
    if (stream.allReady) await stream.allReady;
    return await new Response(stream).text();
  } catch {
    const { renderToString } = await import("react-dom/server");
    return renderToString(tree);
  }
}

function parseCookies(request) {
  const header = request.headers.get("cookie") || "";
  const map = new Map();
  for (const part of header.split(";")) {
    const i = part.indexOf("=");
    if (i > 0) map.set(part.slice(0, i).trim(), decodeURIComponent(part.slice(i + 1).trim()));
  }
  return { get: (k) => map.get(k), has: (k) => map.has(k) };
}

// Extract params from a pattern like ["blog", "[slug]"] against a pathname.
function matchParams(pattern, pathname) {
  const segs = pathname.replace(/^\/+|\/+$/g, "").split("/").filter(Boolean);
  const params = {};
  for (let i = 0; i < pattern.length; i++) {
    const p = pattern[i];
    if (p.startsWith("[...") && p.endsWith("]")) {
      params[p.slice(4, -1)] = segs.slice(i);
      return params;
    }
    if (p.startsWith("[") && p.endsWith("]")) params[p.slice(1, -1)] = segs[i];
  }
  return params;
}

function controlResponse(control, url) {
  if (!control || typeof control !== "object") return null;
  if (control.kind === "redirect") {
    return new Response(null, { status: control.status || 307, headers: { Location: new URL(control.to, url).toString() } });
  }
  if (control.kind === "rewrite") return null; // handled by re-render; v1: ignore
  if (control.kind === "notFound") return new Response("Not Found", { status: 404 });
  if (control.kind === "response" && control.response) return control.response;
  return null;
}

/**
 * Build a web `fetch` handler for one route.
 * opts: { page, layouts[], guards[], loaders[], pattern[], runtime, head, bodyScripts }
 */
export function makeRouteHandler(opts) {
  return async function fetch(request) {
    const url = new URL(request.url);
    const params = matchParams(opts.pattern || [], url.pathname);
    const localsMap = new Map();
    const ctx = {
      url,
      request,
      method: request.method,
      headers: request.headers,
      params,
      searchParams: Object.fromEntries(url.searchParams.entries()),
      cookies: parseCookies(request),
      locals: { get: (k) => localsMap.get(k), set: (k, v) => localsMap.set(k, v) },
      runtime: opts.runtime,
    };

    try {
      for (const guard of opts.guards || []) {
        const r = controlResponse(await guard(ctx), url);
        if (r) return r;
      }
      let loaderData;
      for (const loader of opts.loaders || []) {
        const d = await loader(ctx);
        if (d && typeof d === "object") loaderData = { ...loaderData, ...d };
      }

      let tree = createElement(opts.page, { params, loaderData });
      for (let i = (opts.layouts || []).length - 1; i >= 0; i--) {
        tree = createElement(opts.layouts[i], null, tree);
      }
      const body = await renderTree(tree);
      // opts.head is the full <head> inner captured from the build (charset,
      // viewport, metadata, fonts, global CSS, navigator script).
      const html =
        `<!DOCTYPE html><html lang="en"><head>${opts.head || ""}</head>` +
        `<body>${body}${opts.bodyScripts || ""}</body></html>`;
      return new Response(html, {
        headers: { "content-type": "text/html; charset=utf-8", "x-swift-rust-runtime": opts.runtime || "bun" },
      });
    } catch (err) {
      if (err && err.digest && String(err.digest).startsWith("REDIRECT")) {
        const [, status, ...rest] = String(err.digest).split(";");
        return new Response(null, { status: Number(status) || 307, headers: { Location: rest.join(";") } });
      }
      if (err && (err.digest === "NOT_FOUND" || err.name === "NotFoundError")) {
        return new Response("Not Found", { status: 404 });
      }
      return new Response(`Internal Error: ${err?.message || err}`, { status: 500 });
    }
  };
}
